templates.content:
// Fleet-wide fan-in: every scrape forwards to this one receiver so
// switching sinks only requires editing this single pipeline.
prometheus.remote_write "sink" {
  endpoint {
    url = "http://prom-sink:9091/api/v1/write"

    // Uncomment and fill in for authenticated sinks (Mimir Cloud, etc.)
    // basic_auth {
    //   username = sys.env("REMOTE_WRITE_USER")
    //   password = sys.env("REMOTE_WRITE_PASS")
    // }
  }
}

// Alloy exposes its own metrics on 0.0.0.0:12345/metrics by default.
// Static target keeps this working inside remotecfg-delivered modules,
// where prometheus.exporter.self has surfaced quirks in the past.
prometheus.scrape "alloy_self" {
  targets = [{
    "__address__"      = "127.0.0.1:12345",
    "__metrics_path__" = "/metrics",
    "job"              = "alloy",
  }]
  forward_to      = [prometheus.remote_write.sink.receiver]
  scrape_interval = "15s"
}

// node_exporter lives inside Alloy as prometheus.exporter.unix.
// We enable the conservative default collector set; tune via the
// `include_*` / `exclude_*` args if you need more/fewer metrics.
prometheus.exporter.unix "default" {
}

prometheus.scrape "node" {
  targets         = prometheus.exporter.unix.default.targets
  forward_to      = [prometheus.remote_write.sink.receiver]
  scrape_interval = "30s"
}

// The DSN is read from the collector's environment; never bake secrets
// into pipeline content (they'd be readable by everyone with `read`
// scope on /pipelines).
prometheus.exporter.postgres "default" {
  data_source_names = [sys.env("POSTGRES_DSN")]
}

prometheus.scrape "postgres" {
  targets         = prometheus.exporter.postgres.default.targets
  forward_to      = [prometheus.remote_write.sink.receiver]
  scrape_interval = "30s"
}

prometheus.exporter.elasticsearch "default" {
  address = sys.env("ELASTICSEARCH_URL")
  // Flip these on if you want per-index / per-shard cardinality:
  // indices        = true
  // indices_settings = true
  // cluster_settings = true
  // shards         = true
}

prometheus.scrape "elasticsearch" {
  targets         = prometheus.exporter.elasticsearch.default.targets
  forward_to      = [prometheus.remote_write.sink.receiver]
  scrape_interval = "30s"
}

// nginx-prometheus-exporter is a separate process — Alloy just scrapes
// its /metrics. Default port is 9113.
prometheus.scrape "nginx" {
  targets = [{
    "__address__"      = coalesce(sys.env("NGINX_EXPORTER_ADDR"), "localhost:9113"),
    "__metrics_path__" = "/metrics",
    "job"              = "nginx",
  }]
  forward_to      = [prometheus.remote_write.sink.receiver]
  scrape_interval = "30s"
}

discovery.kubernetes "pods" {
  role = "pod"
}

discovery.relabel "pods" {
  targets = discovery.kubernetes.pods.targets

  // Only keep pods that have prometheus.io/scrape="true".
  rule {
    source_labels = ["__meta_kubernetes_pod_annotation_prometheus_io_scrape"]
    action        = "keep"
    regex         = "true"
  }

  // Honor prometheus.io/path if set.
  rule {
    source_labels = ["__meta_kubernetes_pod_annotation_prometheus_io_path"]
    action        = "replace"
    target_label  = "__metrics_path__"
    regex         = "(.+)"
  }

  // Honor prometheus.io/port if set, rewriting the scrape address.
  rule {
    source_labels = ["__address__", "__meta_kubernetes_pod_annotation_prometheus_io_port"]
    action        = "replace"
    target_label  = "__address__"
    regex         = "([^:]+)(?::\\d+)?;(\\d+)"
    replacement   = "$1:$2"
  }

  // Surface useful pod metadata as labels.
  rule {
    source_labels = ["__meta_kubernetes_namespace"]
    target_label  = "namespace"
  }
  rule {
    source_labels = ["__meta_kubernetes_pod_name"]
    target_label  = "pod"
  }
}

prometheus.scrape "k8s_pods" {
  targets         = discovery.relabel.pods.output
  forward_to      = [prometheus.remote_write.sink.receiver]
  scrape_interval = "30s"
}

// Forwards everything; filter via relabel if you want to drop noisy
// units. The `host` label matches the convention used by the rest of
// the Grafana ecosystem.
loki.source.journal "system" {
  forward_to    = [loki.write.sink.receiver]
  labels        = { host = sys.env("HOSTNAME"), job = "systemd-journal" }
  max_age       = "12h"
}

discovery.docker "containers" {
  host = "unix:///var/run/docker.sock"
}

loki.source.docker "containers" {
  host       = "unix:///var/run/docker.sock"
  targets    = discovery.docker.containers.targets
  forward_to = [loki.write.sink.receiver]
  labels     = { job = "docker" }
}

otelcol.receiver.otlp "default" {
  grpc {
    endpoint = "0.0.0.0:4317"
  }
  http {
    endpoint = "0.0.0.0:4318"
  }

  output {
    traces = [otelcol.exporter.otlp.remote.input]
  }
}

otelcol.exporter.otlp "remote" {
  client {
    endpoint = sys.env("OTLP_EXPORT_ENDPOINT")

    // If your remote is TLS-terminated, flip this:
    // tls {
    //   insecure = false
    // }
    tls {
      insecure = true
    }
  }
}
